// Define competitors and their target pages
const competitors = [
  {
    name: 'Elite Limo Houston',
    domain: 'elitelimohouston.com',
    pages: [
      '/houston-airport-transfers',
      '/corporate-car-service',
      '/wedding-limo'
    ]
  },
  {
    name: 'Limo Star Houston',
    domain: 'limostarhouston.com',
    pages: [
      '/services',
      '/airport-transportation',
      '/wedding-limo-service'
    ]
  },
  {
    name: 'Avante Limo',
    domain: 'avantelimos.com',
    pages: [
      '/houston-airport-limo',
      '/corporate-transportation',
      '/wedding-limousine'
    ]
  }
];

// Keywords to track across all competitors
const keywords = [
  'houston limo service',
  'iah airport transfer',
  'hobby airport car service',
  'corporate car service houston',
  'wedding limo houston',
  'luxury car service houston',
  'houston chauffeur service',
  'sugar land limo',
  'the woodlands car service',
  'houston airport shuttle'
];

// Return items for each competitor
return competitors.map(comp => ({
  json: {
    competitor: comp,
    keywords: keywords,
    date: new Date().toISOString()
  }
}));

// Parse Google search results HTML to extract rankings
const html = $input.first().json.data;
const competitor = $input.first().json.competitor;
const keywords = $input.first().json.keywords;

// Simple rank extraction (simplified - would need proper SERP API for accuracy)
const results = [];
const domain = competitor.domain;

// Check if competitor domain appears in results
const hasRanking = html.includes(domain);
const position = hasRanking ? html.indexOf(domain) : -1;

// Rank estimation (very rough - use SERP API for production)
let estimatedRank = 'Not in top 10';
if (hasRanking) {
  const snippet = html.substring(Math.max(0, position - 200), position + 200);
  if (snippet.includes('result-stats')) estimatedRank = '1-3';
  else if (snippet.includes('Ads')) estimatedRank = 'Ad placement';
  else estimatedRank = '4-10';
}

return [{
  json: {
    date: new Date().toISOString(),
    competitor: competitor.name,
    domain: domain,
    keyword: keywords[0],
    inResults: hasRanking,
    estimatedPosition: estimatedRank,
    fullHtml: html.substring(0, 500) // For debugging
  }
}];

